mapper.select:
SELECT co.cl_order_id, c.client_name, p.product_id, p.product_name, cod.order_qty, cod.detail_id, co.cl_delivery_date AS cl_delivery_date, COALESCE(( SELECT SUM(remaining_qty) FROM ( SELECT pi.inbound_qty - COALESCE(SUM(po.outbound_qty), 0) AS remaining_qty FROM product_inbound pi LEFT JOIN product_outbound po ON pi.product_id = po.product_id AND pi.lot_no = po.lot_no WHERE pi.product_id = p.product_id GROUP BY pi.inbound_id, pi.inbound_qty, pi.expire_date HAVING remaining_qty > 0 ) AS available ), 0) AS stock_qty FROM client_order_detail cod JOIN client_order co ON cod.cl_order_id = co.cl_order_id JOIN client c ON co.client_id = c.client_id JOIN product p ON cod.product_id = p.product_id
co.cl_order_status = 'CONFIRMED' AND (cod.detail_status IS NULL OR cod.detail_status != 'SHIPPED')
GROUP BY co.cl_order_id, c.client_name, p.product_id, p.product_name, cod.order_qty, cod.detail_id, co.cl_delivery_date ORDER BY co.cl_delivery_date ASC LIMIT #{pageStart}, #{perPageNum}

